const hollandQuestions = [{"id": 1, "type": "R", "zh": "使用机器人或智能车套件，搭建一个能够完成指定任务的装置", "en": "Build a robot or smart-vehicle kit that can complete a set task."}, {"id": 2, "type": "I", "zh": "设计一个对照实验，检验某个科学现象或生活说法是否成立", "en": "Design a controlled experiment to test a scientific claim or everyday belief."}, {"id": 3, "type": "A", "zh": "围绕一个校园或社会议题创作短片、播客或图文故事", "en": "Create a short film, podcast, or visual story about a school or social issue."}, {"id": 4, "type": "S", "zh": "为同学讲解学习难点，直到对方真正理解", "en": "Explain a difficult topic to a classmate until they genuinely understand it."}, {"id": 5, "type": "E", "zh": "提出一个校园改进方案，并说服老师或同学支持", "en": "Propose an improvement for school and persuade others to support it."}, {"id": 6, "type": "C", "zh": "用电子表格或数据库整理信息，并确保格式与数据准确", "en": "Organise information in a spreadsheet or database and keep it accurate."}, {"id": 7, "type": "I", "zh": "分析一组真实数据，寻找变量之间的规律、关联或异常", "en": "Analyse real data to find patterns, relationships, or unusual results."}, {"id": 8, "type": "S", "zh": "倾听朋友或同学的困扰，并帮助其梳理可行选择", "en": "Listen to a friend’s concern and help them sort through realistic options."}, {"id": 9, "type": "C", "zh": "为长期项目建立时间表、任务清单和版本管理规则", "en": "Build timelines, task lists, and version rules for a long-term project."}, {"id": 10, "type": "A", "zh": "设计网站或应用程序界面，让信息更直观并具有审美", "en": "Design a website or app interface that is clear and visually engaging."}, {"id": 11, "type": "R", "zh": "把草图制作成可测试的实体原型，例如纸板模型、3D打印件或激光切割件", "en": "Turn a sketch into a testable prototype, such as a cardboard model or 3D print."}, {"id": 12, "type": "E", "zh": "负责团队分工、进度和资源，推动项目按目标完成", "en": "Coordinate roles, time, and resources so a team reaches its goal."}, {"id": 13, "type": "A", "zh": "写小说、剧本、诗歌或非虚构叙事，表达独特视角", "en": "Write fiction, scripts, poetry, or narrative nonfiction from a distinctive viewpoint."}, {"id": 14, "type": "E", "zh": "为社团、活动或公益项目争取赞助、场地或合作机会", "en": "Secure sponsorship, a venue, or partners for a club or community project."}, {"id": 15, "type": "I", "zh": "阅读一篇研究论文，判断它的证据是否足以支持结论", "en": "Read a research paper and judge whether the evidence supports its conclusion."}, {"id": 16, "type": "C", "zh": "检查申请材料、报告或表格中的遗漏、引用和格式问题", "en": "Check applications, reports, or forms for omissions, citations, and formatting errors."}, {"id": 17, "type": "S", "zh": "带领低年级学生完成学习、社团或校园适应任务", "en": "Guide younger students through study, clubs, or adapting to school."}, {"id": 18, "type": "R", "zh": "安装传感器、单片机或电子模块，并排查接线或硬件故障", "en": "Install sensors or electronic modules and troubleshoot wiring or hardware faults."}, {"id": 19, "type": "S", "zh": "设计并主持一次让参与者真正学到东西的工作坊或分享会", "en": "Design and lead a workshop in which participants genuinely learn something."}, {"id": 20, "type": "C", "zh": "管理社团或活动的预算、报销和收支记录", "en": "Manage a club or event budget, expenses, and financial records."}, {"id": 21, "type": "R", "zh": "调整实验装置或工程模型，反复测试直到性能更加稳定", "en": "Adjust an experiment or engineering model and retest it until it works reliably."}, {"id": 22, "type": "E", "zh": "把一个创意做成可执行的产品或服务方案，并向他人路演", "en": "Turn an idea into a workable product or service proposal and pitch it."}, {"id": 23, "type": "I", "zh": "为传染病、气候、交通或市场变化建立简化模型并检验预测", "en": "Build and test a simplified model of disease, climate, traffic, or market change."}, {"id": 24, "type": "A", "zh": "为品牌、社团或活动设计视觉形象、海报或包装", "en": "Design a visual identity, poster, or packaging for a brand, club, or event."}, {"id": 25, "type": "E", "zh": "在意见分歧时进行谈判，争取对团队更有利的方案", "en": "Negotiate during disagreement to reach an outcome that helps the team."}, {"id": 26, "type": "R", "zh": "参与校园活动、展览或舞台的现场搭建与设备布置", "en": "Help set up equipment for an event, exhibition, or stage production."}, {"id": 27, "type": "S", "zh": "通过访谈了解某一群体的真实需求，而不是替他们想当然", "en": "Interview people to understand their real needs instead of assuming them."}, {"id": 28, "type": "I", "zh": "追查一个程序、实验或系统表现异常的原因", "en": "Trace the cause of an unusual result in a program, experiment, or system."}, {"id": 29, "type": "A", "zh": "创作或改编音乐、声音作品或舞台表演", "en": "Create or adapt music, sound work, or a stage performance."}, {"id": 30, "type": "C", "zh": "清洗一组数据，处理重复、缺失或命名不一致的问题", "en": "Clean a dataset by resolving duplicates, missing values, or inconsistent labels."}, {"id": 31, "type": "C", "zh": "为实验、活动或服务设计标准流程和检查清单", "en": "Create standard procedures and checklists for an experiment, event, or service."}, {"id": 32, "type": "A", "zh": "把科学数据或复杂概念转化成有吸引力的信息图或动画", "en": "Turn scientific data or a complex idea into an engaging infographic or animation."}, {"id": 33, "type": "E", "zh": "为一项活动、产品或内容制定推广策略，吸引目标人群参与", "en": "Plan a promotion strategy that attracts the right audience to an activity or product."}, {"id": 34, "type": "R", "zh": "到户外采集并记录水质、土壤、植物或气象样本", "en": "Collect and record water, soil, plant, or weather samples outdoors."}, {"id": 35, "type": "S", "zh": "参与公益或社区项目，并持续跟进帮助是否有效", "en": "Join a community project and follow up on whether the help actually worked."}, {"id": 36, "type": "I", "zh": "比较不同人工智能模型或算法的结果，分析它们为什么出现偏差", "en": "Compare AI models or algorithms and investigate why their results differ."}, {"id": 37, "type": "R", "zh": "操作相机、无人机、测量仪器或实验设备完成一项实地任务", "en": "Use a camera, drone, measuring instrument, or lab equipment in a field task."}, {"id": 38, "type": "S", "zh": "在团队出现误解或冲突时，帮助成员重新沟通并达成共识", "en": "Help a team communicate again and reach agreement after conflict."}, {"id": 39, "type": "A", "zh": "策划一个小型展览、沉浸式体验或主题空间", "en": "Plan a small exhibition, immersive experience, or themed space."}, {"id": 40, "type": "C", "zh": "对大量文件进行分类、命名和归档，让其他人容易查找", "en": "Classify, name, and archive many files so other people can find them easily."}, {"id": 41, "type": "I", "zh": "研究一种疾病、材料或环境问题背后的作用机制", "en": "Study the mechanism behind a disease, material, or environmental problem."}, {"id": 42, "type": "E", "zh": "在信息不完整、时间有限时作出关键决策并承担结果", "en": "Make a key decision with incomplete information and accept responsibility for it."}, {"id": 43, "type": "I", "zh": "核查网络上的健康、科技或社会议题信息是否可靠", "en": "Check whether online health, technology, or social information is trustworthy."}, {"id": 44, "type": "E", "zh": "组织比赛、论坛、义卖或较大型的校园活动", "en": "Organise a competition, forum, charity sale, or large school event."}, {"id": 45, "type": "C", "zh": "维护报名、出勤、库存或借用记录，并及时更新变化", "en": "Maintain registration, attendance, stock, or borrowing records and update changes."}, {"id": 46, "type": "S", "zh": "为健康、安全、心理或学习习惯制作易懂的科普指导", "en": "Create clear public guidance about health, safety, wellbeing, or study habits."}, {"id": 47, "type": "R", "zh": "为学习、运动或日常生活中的问题设计并制作一个实用装置", "en": "Design and build a practical device for a learning, sport, or everyday problem."}, {"id": 48, "type": "A", "zh": "重新设计一件日常用品，使它更好看、更有个性或更易使用", "en": "Redesign an everyday object to make it more attractive, distinctive, or usable."}, {"id": 49, "type": "A", "zh": "用摄影、插画、建筑模型或数字艺术表达一个想法", "en": "Use photography, illustration, models, or digital art to express an idea."}, {"id": 50, "type": "C", "zh": "按照明确标准审核一批作品、数据或材料的质量", "en": "Review a set of work, data, or materials against clear quality standards."}, {"id": 51, "type": "R", "zh": "对模型、产品或设备进行安全与耐用性测试，找出故障点", "en": "Test a model, product, or device for safety and durability and find failure points."}, {"id": 52, "type": "I", "zh": "提出一个尚无明确答案的问题，并规划如何收集证据", "en": "Raise an open question and plan how to collect evidence for it."}, {"id": 53, "type": "E", "zh": "分析用户或受众需求后，决定项目优先级和发展方向", "en": "Analyse user needs and decide a project’s priorities and direction."}, {"id": 54, "type": "S", "zh": "陪伴需要额外支持的人完成一项活动或学习任务", "en": "Support someone who needs extra help to complete a task or activity."}, {"id": 55, "type": "S", "zh": "与不同背景的人合作，创造更加包容的活动或服务", "en": "Work with people from different backgrounds to create a more inclusive service."}, {"id": 56, "type": "R", "zh": "在创客空间或实验室按照安全规范使用工具完成制作", "en": "Use tools safely in a makerspace or laboratory to complete a build."}, {"id": 57, "type": "E", "zh": "在辩论、模拟联合国或公共议题讨论中影响他人的判断", "en": "Influence people’s judgement in debate, Model UN, or public-issue discussion."}, {"id": 58, "type": "A", "zh": "面对开放式任务，尝试一种没有现成模板的原创方案", "en": "Try an original approach to an open task with no ready-made template."}, {"id": 59, "type": "C", "zh": "把项目进展整理成结构清晰的仪表盘、周报或汇总表", "en": "Turn project progress into a clear dashboard, weekly report, or summary."}, {"id": 60, "type": "I", "zh": "把复杂问题拆成若干可验证的假设，逐一排除不合理解释", "en": "Break a complex problem into testable hypotheses and rule out weak explanations."}];
const hollandTypes = {"R": {"zh": "现实型", "en": "Realistic", "color": "#1698b5", "coreZh": "你更容易被能动手、能测试、能看见结果的任务吸引。", "coreEn": "You are drawn to practical tasks that can be built, tested, and seen.", "detailZh": "工具、设备、结构、现场和清楚的产出，会让你更容易进入状态。你通常愿意边做边修正，也能忍受反复调试，只要变化是看得见的。", "detailEn": "Tools, systems, field settings, and visible outcomes help you engage. You often learn by doing and can tolerate repeated testing when progress is tangible.", "verifyZh": "找一个需要制作、测量或调试的真实任务，记录你是否愿意持续改进，而不只是享受完成那一刻。", "verifyEn": "Try a real task involving building, measuring, or troubleshooting, and notice whether you enjoy the repeated improvement as much as the finished result."}, "I": {"zh": "研究型", "en": "Investigative", "color": "#d0a11f", "coreZh": "你喜欢追问原因，并用证据把复杂问题弄清楚。", "coreEn": "You like tracing causes and using evidence to make sense of complex problems.", "detailZh": "建模、实验、阅读论文、处理数据和诊断异常，往往比照着步骤完成任务更能抓住你的注意力。你需要理解“为什么”，也愿意为一个问题多想一层。", "detailEn": "Modelling, experiments, research papers, data, and diagnosis tend to hold your attention more than following fixed steps. You want to understand why and are willing to dig deeper.", "verifyZh": "选择一个没有现成答案的问题，做一次小型文献或数据调查，看看你是否享受证据不完整时的推理过程。", "verifyEn": "Choose an open question and run a small literature or data investigation. Notice whether you enjoy reasoning when evidence is incomplete."}, "A": {"zh": "艺术型", "en": "Artistic", "color": "#3f996f", "coreZh": "你在意表达、体验和原创空间，希望事情带有自己的判断。", "coreEn": "You care about expression, experience, and room for original judgement.", "detailZh": "写作、视觉、叙事、设计和开放式任务更容易激发你。你未必排斥技术或分析，但通常希望它们最终服务于一种更有个性、更有感受的表达。", "detailEn": "Writing, visuals, narrative, design, and open-ended work energise you. You may enjoy technical or analytical work too, especially when it supports a distinctive form of expression.", "verifyZh": "完成一个小作品并做两轮修改，观察你是否愿意同时面对审美、用户反馈和现实限制。", "verifyEn": "Complete a small creative work and revise it twice. Notice whether you enjoy balancing aesthetics, feedback, and practical constraints."}, "S": {"zh": "社会型", "en": "Social", "color": "#d44c52", "coreZh": "你愿意理解人、支持人，也在意一件事对群体是否真的有帮助。", "coreEn": "You are motivated by understanding people, supporting them, and improving real situations.", "detailZh": "讲解、倾听、辅导、协作和需求访谈会给你更直接的意义感。社会型并不等于外向；安静、耐心、愿意长期陪伴，也可能是很强的社会型表现。", "detailEn": "Teaching, listening, mentoring, collaboration, and needs research give you a direct sense of purpose. Social interest does not require being highly extroverted; patience and sustained support matter too.", "verifyZh": "尝试一次持续性的同伴支持或需求访谈，重点观察你是否愿意处理误解、重复沟通和真实反馈。", "verifyEn": "Try sustained peer support or a needs interview, and notice whether you can stay engaged through misunderstanding, repetition, and real feedback."}, "E": {"zh": "企业型", "en": "Enterprising", "color": "#7357b5", "coreZh": "你喜欢推动事情发生，影响决策，并把人和资源组织起来。", "coreEn": "You enjoy moving things forward, influencing decisions, and organising people and resources.", "detailZh": "路演、谈判、项目管理、营销和关键决策会让你更有投入感。你的重点往往不只是提出好点子，还包括让别人理解、加入并把事情做成。", "detailEn": "Pitching, negotiation, project leadership, marketing, and consequential decisions engage you. Your interest is not only in ideas, but in gaining support and making them happen.", "verifyZh": "负责一次有真实目标和受众的项目，看看你是否愿意承担不确定性、协调分歧并对结果负责。", "verifyEn": "Lead a project with a real audience and outcome. Notice whether you can handle uncertainty, disagreement, and responsibility for results."}, "C": {"zh": "常规型", "en": "Conventional", "color": "#50697c", "coreZh": "你擅长建立秩序，让信息、流程和系统可靠地运转。", "coreEn": "You are comfortable creating order and keeping information, processes, and systems reliable.", "detailZh": "准确、分类、记录、质量控制和清楚的规则会让你更安心。你常能发现别人忽略的细节，也愿意把一次性的做法整理成可复用的流程。", "detailEn": "Accuracy, classification, records, quality control, and clear rules suit you. You often notice overlooked details and turn one-off work into repeatable processes.", "verifyZh": "为一个真实活动建立预算、数据表或工作流，观察你是否享受长期维护，而不只是第一次搭建。", "verifyEn": "Build a budget, dataset, or workflow for a real activity and see whether you enjoy maintaining it, not only setting it up."}};
const hollandPairZh = {"RI": "你既想理解原理，也愿意把结论放进实验、设备或真实系统中检验。纯理论和纯执行都可能让你觉得少了一块。", "RA": "你喜欢把创意做成看得见的结果。设计工程、产品开发和交互体验常能同时容纳制作与表达。", "RS": "你更愿意通过实际行动解决人的问题。健康技术、工程服务和以用户为中心的设计会比单纯讨论更有吸引力。", "RE": "你对“做出来”和“推动落地”都有兴趣。工程管理、产品开发和运营型项目可能让你更有掌控感。", "RC": "你重视实际结果，也希望过程可靠、可检查。测试、质量、制造和系统实施通常符合这种节奏。", "IA": "你对研究与表达都有要求，常会追问：复杂内容怎样才能被理解、被看见或被重新设计。", "IS": "你愿意先把问题研究清楚，再考虑怎样帮助人。心理、健康、社会研究和用户研究都需要这种耐心。", "IE": "你喜欢用分析支持判断，并愿意把结论转成决策。经济、金融、商业分析和政策评估常见这种组合。", "IC": "你能在研究和结构之间找到平衡。数据、实验、软件系统和质量管理会同时用到求证与严谨。", "AS": "你重视表达，也关心受众的真实感受。传媒、心理传播、视觉沟通和教育内容可能更容易让你投入。", "AE": "你既想创造，也希望作品产生影响。品牌、媒体、设计管理和文化产业常需要把审美转成行动。", "AC": "你有创意，同时在意细节和完成度。视觉系统、信息设计和交互产品会让原创与规范一起出现。", "SE": "你擅长在人与目标之间搭桥。管理、国际贸易、传媒运营和组织发展都需要沟通、推动和协调。", "SC": "你关心人，也希望服务过程稳定可靠。心理服务、公共管理和社会项目运营会考验耐心与流程意识。", "EC": "你既能组织资源，也愿意管住细节。会计、金融运营、商业信息系统和管理岗位常需要这种组合。"};
const hollandPairEn = {"RI": "You want to understand how things work and test ideas in real systems. Pure theory or pure execution may each feel incomplete.", "RA": "You enjoy turning creative ideas into visible, usable outcomes. Design engineering, product development, and interaction work often combine both needs.", "RS": "You prefer helping people through practical action. Health technology, service engineering, and user-centred design may feel more meaningful than discussion alone.", "RE": "You like building things and pushing them into action. Product development, engineering management, and operational projects can suit this drive.", "RC": "You value practical results and dependable processes. Testing, quality, manufacturing, and implementation often match this working rhythm.", "IA": "You want both investigation and expression, often asking how complex ideas can be understood, visualised, or redesigned.", "IS": "You prefer to understand a problem carefully before deciding how to help. Psychology, health, social research, and user research often require this patience.", "IE": "You like using analysis to support decisions and turning evidence into action. Economics, finance, business analytics, and policy work often use this combination.", "IC": "You balance inquiry with structure. Data, experiments, software systems, and quality work all reward evidence and precision.", "AS": "You care about expression and about how people receive it. Media, visual communication, health communication, and educational content can fit this mix.", "AE": "You want to create and to have an impact. Brand, media, design management, and cultural industries often connect creativity with influence.", "AC": "You are creative but also care about detail and finish. Visual systems, information design, and interaction products combine originality with standards.", "SE": "You connect people with goals. Management, international trade, media operations, and organisational work rely on communication, influence, and coordination.", "SC": "You care about people and about dependable service. Psychology services, public administration, and social programmes reward patience and process awareness.", "EC": "You can organise resources while keeping details under control. Accounting, financial operations, business information systems, and management often need both."};
